<script setup lang="ts">
import axios from 'axios';

const router = useRouter();
const route = useRoute();

const step = ref<'splash' | 'welcome' | 'login' | 'register'>('splash');
const email = ref('');
const password = ref('');
const displayName = ref('');
const password2 = ref('');
const error = ref('');
const loading = ref(false);
const googleEnabled = ref(false);
const splashDone = ref(false);
const authReady = ref(false);
const showCard = ref(false);

onMounted(async () => {
  // Check Google OAuth via LumiChat's public endpoint
  try {
    const r = await fetch('/lc/auth/methods', { credentials: 'same-origin' });
    if (r.ok) {
      const d = await r.json();
      if (d.google) googleEnabled.value = true;
    }
  } catch {}

  // Check if already logged in via PB cookie
  try {
    const r = await fetch('/lc/auth/me', { credentials: 'include' });
    if (r.ok) {
      authReady.value = true;
      // Wait for splash then auto-login
      waitForSplash(() => doFreqtradeAutoLogin());
      return;
    }
  } catch {}

  // Not logged in — show auth after splash
  authReady.value = true;
  waitForSplash(() => {
    step.value = 'welcome';
    // Delay card entrance for smooth transition
    setTimeout(() => { showCard.value = true; }, 50);
  });
});

// Splash minimum 2s
setTimeout(() => { splashDone.value = true; }, 2000);

function waitForSplash(fn: () => void) {
  if (splashDone.value) { fn(); return; }
  const stop = watch(splashDone, (v) => { if (v) { stop(); fn(); } });
}

function googleLogin() {
  const redirect = encodeURIComponent('/lumitrade/');
  window.location.href = `/lc/auth/oauth-start?provider=google&redirect=${redirect}`;
}

async function continueWithEmail() {
  error.value = '';
  if (!email.value.trim()) { error.value = 'Please enter your email'; return; }
  loading.value = true;
  try {
    const r = await fetch('/lc/auth/check-email', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email: email.value.trim() }),
    });
    const d = await r.json();
    step.value = d.exists ? 'login' : 'register';
  } catch {
    step.value = 'login';
  }
  loading.value = false;
}

async function doLogin() {
  error.value = '';
  if (!password.value) { error.value = 'Password required'; return; }
  loading.value = true;
  try {
    const r = await fetch('/lc/auth/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ email: email.value.trim(), password: password.value }),
    });
    if (!r.ok) {
      const d = await r.json().catch(() => ({}));
      if (d.message?.includes('authenticate') || d.error?.includes('Google')) {
        error.value = 'This account uses Google login';
        loading.value = false;
        return;
      }
      error.value = d.error || d.message || 'Login failed';
      loading.value = false;
      return;
    }
    await doFreqtradeAutoLogin();
  } catch (e: any) {
    error.value = e.message || 'Login failed';
    loading.value = false;
  }
}

async function doRegister() {
  error.value = '';
  if (!displayName.value.trim()) { error.value = 'Name required'; return; }
  if (password.value.length < 8) { error.value = 'Password must be at least 8 characters'; return; }
  if (password.value !== password2.value) { error.value = 'Passwords do not match'; return; }
  loading.value = true;
  try {
    const r = await fetch('/lc/auth/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ email: email.value.trim(), password: password.value, name: displayName.value.trim() }),
    });
    if (!r.ok) {
      const d = await r.json().catch(() => ({}));
      error.value = d.error || d.message || 'Registration failed';
      loading.value = false;
      return;
    }
    await doFreqtradeAutoLogin();
  } catch (e: any) {
    error.value = e.message || 'Registration failed';
    loading.value = false;
  }
}

async function doFreqtradeAutoLogin() {
  loading.value = true;
  try {
    const { data: creds } = await axios.get('/lumitrade/auto-auth', { timeout: 3000 });
    if (!creds?.username) throw new Error('no creds');
    const apiUrl = window.location.origin + '/lumitrade';
    const { data: tokenResp } = await axios.post(
      `/lumitrade/api/v1/token/login`, {},
      { auth: { username: creds.username, password: creds.password }, timeout: 5000 },
    );
    if (!tokenResp?.access_token) throw new Error('no token');

    const BOT_ID = 'ftbot.0';
    const authStorage: Record<string, any> = {
      [BOT_ID]: {
        botName: creds.botName || 'LumiTrade', apiUrl,
        username: creds.username, refreshToken: tokenResp.refresh_token,
        accessToken: tokenResp.access_token, autoRefresh: true, sortId: 0,
      },
    };
    try {
      const { data: bt } = await axios.post(
        `/lumitrade/bt/api/v1/token/login`, {},
        { auth: { username: creds.username, password: creds.password }, timeout: 5000 },
      );
      if (bt?.access_token) {
        authStorage['ftbot.1'] = {
          botName: 'Backtest', apiUrl: window.location.origin + '/lumitrade/bt',
          username: creds.username, refreshToken: bt.refresh_token,
          accessToken: bt.access_token, autoRefresh: true, sortId: 1,
        };
      }
    } catch {}

    localStorage.setItem('ftAuthLoginInfo', JSON.stringify(authStorage));
    localStorage.setItem('ftSelectedBot', BOT_ID);
    const redirect = (route.query.redirect as string) || '/trade';
    window.location.href = import.meta.env.BASE_URL + redirect.replace(/^\//, '');
  } catch {
    error.value = 'Failed to connect to trading engine';
    step.value = 'welcome';
    showCard.value = true;
    loading.value = false;
  }
}
</script>

<template>
  <div class="lt-login-bg">
    <!-- Splash screen (ball drop animation) -->
    <div v-if="step === 'splash'" class="lt-splash">
      <div class="lt-splash-scene">
        <svg class="lt-splash-ball" viewBox="0 0 40 40" width="64" height="64" fill="none" xmlns="http://www.w3.org/2000/svg">
          <circle cx="20" cy="20" r="20" fill="#10a37f"/>
          <polyline points="10 26 17 18 23 22 30 14" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
          <polyline points="25 14 30 14 30 19" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
        </svg>
        <div class="lt-splash-title">Lumi<span class="lt-accent">Trade</span></div>
      </div>
    </div>

    <!-- Auth card -->
    <div v-if="step !== 'splash'" class="lt-login-card" :class="{ 'lt-card-enter': showCard }">
      <!-- Logo -->
      <div class="lt-login-logo">
        <svg viewBox="0 0 40 40" width="48" height="48" fill="none" xmlns="http://www.w3.org/2000/svg">
          <circle cx="20" cy="20" r="20" fill="#10a37f"/>
          <polyline points="10 26 17 18 23 22 30 14" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
          <polyline points="25 14 30 14 30 19" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
        </svg>
        <h1 class="lt-login-title">Lumi<span class="lt-accent">Trade</span></h1>
      </div>

      <!-- Loading state (auto-login in progress) -->
      <div v-if="loading && step === 'welcome' && !error" class="lt-login-form" style="align-items:center">
        <p class="lt-login-sub">Connecting...</p>
      </div>

      <!-- Step: Welcome -->
      <div v-else-if="step === 'welcome'" class="lt-login-form">
        <p class="lt-login-heading">Welcome</p>
        <p class="lt-login-sub">Log in or create an account</p>

        <button v-if="googleEnabled" class="lt-google-btn" @click="googleLogin">
          <svg width="18" height="18" viewBox="0 0 48 48"><path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.08 17.74 9.5 24 9.5z"/><path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/><path fill="#FBBC05" d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24c0 3.88.92 7.54 2.56 10.78l7.97-6.19z"/><path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.18 1.48-4.97 2.31-8.16 2.31-6.26 0-11.57-3.59-13.46-8.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/></svg>
          <span>Continue with Google</span>
        </button>
        <div v-if="googleEnabled" class="lt-divider"><span>or</span></div>

        <input v-model="email" class="lt-input" type="email" placeholder="Email" autocomplete="email" @keydown.enter="continueWithEmail" />
        <button class="lt-btn-primary" :disabled="loading" @click="continueWithEmail">
          {{ loading ? 'Loading...' : 'Continue' }}
        </button>
        <p v-if="error" class="lt-error">{{ error }}</p>
      </div>

      <!-- Step: Login -->
      <div v-else-if="step === 'login'" class="lt-login-form">
        <p class="lt-login-heading">Welcome back</p>
        <p class="lt-login-sub">{{ email }}</p>
        <input v-model="password" class="lt-input" type="password" placeholder="Password" autocomplete="off" @keydown.enter="doLogin" />
        <button class="lt-btn-primary" :disabled="loading" @click="doLogin">
          {{ loading ? 'Logging in...' : 'Continue' }}
        </button>
        <p class="lt-back-link"><a @click="step = 'welcome'; error = ''">Use a different email</a></p>
        <p v-if="error" class="lt-error">{{ error }}</p>
      </div>

      <!-- Step: Register -->
      <div v-else-if="step === 'register'" class="lt-login-form">
        <p class="lt-login-heading">Create account</p>
        <p class="lt-login-sub">{{ email }}</p>
        <input v-model="displayName" class="lt-input" type="text" placeholder="Display name" autocomplete="off" />
        <input v-model="password" class="lt-input" type="password" placeholder="Password (min 8 chars)" autocomplete="off" />
        <input v-model="password2" class="lt-input" type="password" placeholder="Confirm password" autocomplete="off" @keydown.enter="doRegister" />
        <button class="lt-btn-primary" :disabled="loading" @click="doRegister">
          {{ loading ? 'Creating...' : 'Create account' }}
        </button>
        <p class="lt-back-link"><a @click="step = 'welcome'; error = ''">Use a different email</a></p>
        <p v-if="error" class="lt-error">{{ error }}</p>
      </div>
    </div>
  </div>
</template>

